results.response:
^ch:my_data_chan ::int buf:5;
^frk:producer_task ^lp {n:5} {^tx:my_data_chan {v:$idx}};
$collected_items = [];
^tmo:10 <<
  ^lp {n:5} <<
    ^rx:my_data_chan ->$item;
    !mod @mem {path:"$collected_items[]" val:$item};
  >>
>> ^el {~err {code:E_TIMEOUT lvl:warn msg:"Collection timed out"}};
^jn [producer_task];

